from haystack import Pipeline
from haystack.components.builders import component_schema

class TypeMismatchDetector:
    def __init__(self, pipeline: Pipeline):
        self.pipeline = pipeline
        self.mismatches = []

    def scan(self):
        connections = self.pipeline._connections
        for source, target in connections.items():
            source_comp = self.pipeline.get_component(source)
            target_comp = self.pipeline.get_component(target)

            source_schema = getattr(source_comp, '_output_schema', {})
            target_schema = getattr(target_comp, '_input_schema', {})

            for expected_type in target_schema.values():
                if source_schema and source_schema.get('type') != expected_type:
                    self.mismatches.append({
                        'source': source, 'target': target,
                        'expected': expected_type, 'actual': source_schema.get('type')
                    })
        return self.mismatches

# Usage
detector = TypeMismatchDetector(my_rag_pipeline)
mismatches = detector.scan()
print(f'Found {len(mismatches)} type mismatches')

