from haystack.dataclasses import Document

import numpy as np

class RetrieverValidator:
    def __init__(self, retriever):
        self.retriever = retriever

    def validate_relevance(self, test_queries, expected_docs, threshold=0.3):
        failures = []
        for query, expected_doc in zip(test_queries, expected_docs):
            result = self.retriever.run(query=query, top_k=3)
            top_doc = result['documents'][0]

            score = top_doc.score if hasattr(top_doc, 'score') else 0
            relevance_match = any(expected_doc.content in top_doc.content 
                                for expected_doc in expected_docs)

            if score < threshold or not relevance_match:
                failures.append({
                    'query': query,
                    'score': score,
                    'relevant': relevance_match
                })
        return {
            'avg_score': np.mean([f['score'] for f in failures]),
            'failure_rate': len(failures)/len(test_queries),
            'failures': failures
        }

# Usage
test_queries = ["What is Haystack?"]
expected_docs = [Document(content="Haystack is an LLM framework")]
validator = RetrieverValidator(retriever)
results = validator.validate_relevance(test_queries, expected_docs)
print(results)

