from haystack import Pipeline, component
from typing import Any, Dict, List
from haystack.dataclasses import Document

@component
class TypeConverter:
    @component.output_types(documents=List[Document], metadata=Dict[str, Any])
    def run(self, input_data: Any):
        if isinstance(input_data, list) and input_data and not isinstance(input_data[0], Document):
            # Convert list of dicts to Documents
            return {
                'documents': [Document(content=str(item)) for item in input_data],
                'metadata': {'converted': True}
            }
        return {'documents': input_data, 'metadata': {'converted': False}}

# Fix pipeline
pipeline = Pipeline()
pipeline.add_component("converter", TypeConverter())
pipeline.add_component("retriever", retriever)
pipeline.connect("converter.documents", "retriever.documents")

from haystack.components.retrievers import InMemoryBM25Retriever, InMemoryEmbeddingRetriever

@component
class RelevanceRouter:
    @component.output_types(bm25_docs=List[Document], embedding_docs=List[Document], route='str')
    def run(self, query: str, bm25_docs: List[Document], embedding_docs: List[Document]):
        bm25_avg_score = sum(doc.score or 0 for doc in bm25_docs[:3]) / 3

        if bm25_avg_score > 0.2:
            return {'bm25_docs': bm25_docs, 'embedding_docs': [], 'route': 'bm25'}
        else:
            return {'bm25_docs': [], 'embedding_docs': embedding_docs, 'route': 'embedding'}

# Fixed pipeline
pipeline = Pipeline()
pipeline.add_component("bm25", InMemoryBM25Retriever())
pipeline.add_component("embedding", InMemoryEmbeddingRetriever())
pipeline.add_component("router", RelevanceRouter())
pipeline.connect("bm25.documents", "router.bm25_docs")
pipeline.connect("embedding.documents", "router.embedding_docs")

